-- Артефакты-placeholders для проекта 5
INSERT INTO t_p61016064_digital_innovation_i.workspace_artifacts
  (project_id, title, artifact_type, content, summary, mode, created_by)
VALUES
(5, 'As-is процесс: Обработка контрольных замечаний', 'analysis',
 '# As-is процесс: Обработка контрольных замечаний\n\n## Участники\n- Контролёр / аудитор / владелец процесса\n- Аналитик внутреннего контроля\n- Руководитель направления\n- Исполнители корректирующих мероприятий\n\n## Шаги процесса\n1. **Поступление замечания** — через почту, Excel, Word, внутренние формы\n2. **Первичное чтение** — аналитик вручную интерпретирует текст\n3. **Определение типа** — субъективная классификация\n4. **Назначение маршрута** — по опыту аналитика\n5. **Формирование карточки** — копипаст из нескольких источников\n6. **Контроль статуса** — периодический опрос исполнителей\n7. **Подготовка сводки** — 2–4 часа еженедельно\n\n## Ключевые проблемы\n- Разрозненные каналы без единой точки входа\n- Нет стандарта описания замечания\n- Ручная классификация — субъективная и непоследовательная\n- Нет прозрачности статусов без запроса к аналитику\n- Подготовка отчётности занимает несоразмерно много времени',
 'Текущий процесс обработки замечаний: 7 шагов, все ручные, разрозненные инструменты, субъективная классификация',
 'analyst', 1),

(5, 'AI Assessment: Где нужен AI, а где нет', 'analysis',
 '# AI Assessment для кейса: Обработка контрольных замечаний\n\n## Где AI рекомендован\n\n### 1. Суммаризация и черновик карточки (GenAI)\n- **Что:** автоматическое извлечение сути замечания и заполнение полей карточки\n- **Тип:** GenAI (YandexGPT, GPT-4)\n- **Эффект:** -60–70% времени на оформление\n- **Риски:** галлюцинации, необходим human review\n\n### 2. Классификация типа отклонения (ML)\n- **Что:** автоматическое присвоение категории по тексту замечания\n- **Тип:** классический ML / fine-tuned классификатор\n- **Эффект:** однородная классификация, скорость мгновенно vs 15–20 мин\n- **Риски:** нужен обучающий датасет 100+ примеров\n\n## Где AI НЕ нужен\n\n### Маршрутизация → Rule Engine\n- Матрица тип × подразделение = ответственный\n- Не AI — просто чёткие правила\n\n### Контроль статусов → Workflow/BPM\n- Статусная машина, уведомления, SLA\n\n### Дашборд руководителя → BI\n- Агрегация из структурированного реестра\n\n## Итог\n**Рекомендуемый стек:** реестр + workflow + rule engine + AI только для NLP-задач\n**Контроль:** human-in-the-loop обязателен для всех AI-решений\n**Следующий шаг:** создать структурированный реестр — без него AI не имеет смысла',
 'AI нужен для NLP-задач: суммаризация и классификация. Маршрутизация и статусы — не AI, а workflow и rule engine.',
 'analyst', 1);
